(refactored out of the v1 path); it emits the per-phase object
without the outer schema envelope.

Parser mutual-exclusion in Source/UniPlanOptionParsing.cpp:

```cpp
bool ParsePhaseReadinessOptions(const std::vector<std::string> &InArgs,
                                FPhaseReadinessOptions &OutOptions,
                                std::string &OutError)
{
    for (size_t I = 0; I < InArgs.size(); ++I)
    {
        const std::string &Tok = InArgs[I];
        if (ConsumeCommonOptions(Tok, InArgs, I, OutOptions, OutError))
            continue;
        if (Tok == "--topic" && I + 1 < InArgs.size())
        {
            OutOptions.mTopic = InArgs[++I];
            continue;
        }
        if (Tok == "--phase" && I + 1 < InArgs.size())
        {
            OutOptions.mPhaseIndex = std::stoi(InArgs[++I]);
            continue;
        }
        if (Tok == "--all-phases")
        {
            OutOptions.mbAllPhases = true;
            continue;
        }
        OutError = "unknown token: " + Tok;
        return false;
    }

    if (OutOptions.mbAllPhases && OutOptions.mPhaseIndex.has_value())
    {
        OutError = "--all-phases and --phase are mutually exclusive";
        return false;
    }
    return true;
}
```

