Reference parser helper (adds the third companion flag on top of
the existing TryConsumeStringOrFileOption). The shape in the
contract file stays authoritative; this snippet just shows the
branch internal logic for clarity:

```cpp
bool TryConsumeStringOrFileOrAppendFileOption(
    const std::string &InToken,
    const std::vector<std::string> &InArgs,
    size_t &InOutIndex,
    const std::string &InFlagName,
    const std::string &InFileFlagName,
    const std::string &InAppendFlagName,
    const std::string &InFieldName,
    std::string &OutValue,
    bool &OutValueSet,
    std::set<std::string> &OutAppendFields,
    std::string &OutError)
{
    if (InToken == InFlagName)
    {
        if (OutValueSet) {
            OutError = "mutually exclusive flags for " + InFieldName;
            return false;
        }
        if (InOutIndex + 1 >= InArgs.size()) {
            OutError = InFlagName + " requires a value";
            return false;
        }
        OutValue = InArgs[++InOutIndex];
        OutValueSet = true;
        return true;
    }
    if (InToken == InFileFlagName)
    {
        if (OutValueSet) {
            OutError = "mutually exclusive flags for " + InFieldName;
            return false;
        }
        if (InOutIndex + 1 >= InArgs.size()) {
            OutError = InFileFlagName + " requires a path";
            return false;
        }
        const std::string Path = InArgs[++InOutIndex];
        if (!TryReadFileToString(Path, OutValue, OutError)) {
            return false;
        }
        OutValueSet = true;
        return true;
    }
    if (InToken == InAppendFlagName)
    {
        if (OutValueSet) {
            OutError = "mutually exclusive flags for " + InFieldName;
            return false;
        }
        if (InOutIndex + 1 >= InArgs.size()) {
            OutError = InAppendFlagName + " requires a path";
            return false;
        }
        const std::string Path = InArgs[++InOutIndex];
        if (!TryReadFileToString(Path, OutValue, OutError)) {
            return false;
        }
        OutValueSet = true;
        OutAppendFields.insert(InFieldName);
        return true;
    }
    return false;
}
